const PORTADA_INFORME = (ot, empresa, anio, placa) => {
    const p = placa || {};
    // Banner ocupa todo el ancho de la página
    const bannerW = Math.round(18 * 360000);   // 18cm en EMU
    const bannerH = Math.round(11.45 * 360000); // 11.45cm en EMU
    const bannerXml = `<w:p><w:pPr><w:spacing w:after="0" w:before="0"/><w:jc w:val="center"/></w:pPr><w:r><w:rPr><w:noProof/></w:rPr><w:drawing><wp:inline xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing"><wp:extent cx="${bannerW}" cy="${bannerH}"/><wp:effectExtent l="0" t="0" r="0" b="0"/><wp:docPr id="10" name="banner"/><wp:cNvGraphicFramePr><a:graphicFrameLocks xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" noChangeAspect="1"/></wp:cNvGraphicFramePr><a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"><a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:pic xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:nvPicPr><pic:cNvPr id="10" name="banner"/><pic:cNvPicPr><a:picLocks noChangeAspect="1"/></pic:cNvPicPr></pic:nvPicPr><pic:blipFill><a:blip r:embed="rId10"/><a:stretch><a:fillRect/></a:stretch></pic:blipFill><pic:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="${bannerW}" cy="${bannerH}"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom></pic:spPr></pic:pic></a:graphicData></a:graphic></wp:inline></w:drawing></w:r></w:p>`;

    const infoMotor = [
        p.marca ? ('MARCA: ' + p.marca) : '',
        p.pot   ? ('POTENCIA: ' + p.pot + ' kW') : '',
        p.rpm   ? ('RPM: ' + p.rpm) : '',
        p.frame ? ('FRAME: ' + p.frame) : '',
    ].filter(Boolean).join('   |   ');

    return [
        // Espacios superiores para centrar verticalmente
        `<w:p><w:pPr><w:spacing w:before="1800" w:after="0"/></w:pPr></w:p>`,
        // Subtítulo superior
        `<w:p><w:pPr><w:spacing w:before="0" w:after="120"/><w:ind w:left="500"/></w:pPr><w:r><w:rPr><w:rFonts w:ascii="Calibri" w:hAnsi="Calibri"/><w:color w:val="5A6A7A"/><w:sz w:val="22"/><w:szCs w:val="22"/></w:rPr><w:t>REPORTE TECNICO  OT ${xE(ot)}  |  ${xE(String(anio))}</w:t></w:r></w:p>`,
        // Título principal grande
        `<w:p><w:pPr><w:spacing w:before="0" w:after="80"/><w:ind w:left="500"/></w:pPr><w:r><w:rPr><w:rFonts w:ascii="Calibri" w:hAnsi="Calibri"/><w:b/><w:color w:val="1A1A2E"/><w:sz w:val="64"/><w:szCs w:val="64"/></w:rPr><w:t>SERVICIO MANTENIMIENTO</w:t></w:r></w:p>`,
        // Subtítulo
        `<w:p><w:pPr><w:spacing w:before="0" w:after="60"/><w:ind w:left="500"/></w:pPr><w:r><w:rPr><w:rFonts w:ascii="Calibri" w:hAnsi="Calibri"/><w:color w:val="2C3E50"/><w:sz w:val="24"/><w:szCs w:val="24"/></w:rPr><w:t>MAQUINAS ELÉCTRICAS ROTATIVAS</w:t></w:r></w:p>`,
        // Empresa
        `<w:p><w:pPr><w:spacing w:before="0" w:after="40"/><w:ind w:left="500"/></w:pPr><w:r><w:rPr><w:rFonts w:ascii="Calibri" w:hAnsi="Calibri"/><w:color w:val="666666"/><w:sz w:val="20"/><w:szCs w:val="20"/></w:rPr><w:t xml:space="preserve">Cliente: ${xE(empresa)}${infoMotor ? '   —   ' + xE(infoMotor) : ''}</w:t></w:r></w:p>`,
        // Espacio antes del banner
        `<w:p><w:pPr><w:spacing w:before="0" w:after="1800"/></w:pPr></w:p>`,
        // Banner
        bannerXml,
        // Salto de página
        `<w:p><w:pPr><w:pageBreakBefore/><w:spacing w:before="0" w:after="0"/></w:pPr></w:p>`,
    ].join('');
};

